import { html, customElement } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import type { FormSecurityForUser } from '@umbraco-forms/generated';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE } from '../../../entities.js';
import { FormsSecurityUserDetailRepository } from '../../../repository/index.js';
import type { FormsUserSecurityDeleteConfirmModalData } from './index.js';

@customElement('forms-user-security-delete-confirm-modal')
export class FormsUserSecurityDeleteConfirmModalElement extends UmbModalBaseElement<FormsUserSecurityDeleteConfirmModalData> {

	#userSecurityToDelete?: FormSecurityForUser | null;

	#userSecurityDetailRepository = new FormsSecurityUserDetailRepository(this);

	async connectedCallback() {
		super.connectedCallback();

		if (!this.data?.unique) return;

		const { data } = await this.#userSecurityDetailRepository.requestByUnique(this.data.unique);
		this.#userSecurityToDelete = data;

		this.requestUpdate();
	}

	async #deleteUserSecurity(event: PointerEvent) {
		event.stopPropagation();

		if (this.data?.unique) {
			await this.#userSecurityDetailRepository.delete(this.data.unique);

			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
				entityType: FORMS_SECURITY_USER_FOLDER_ENTITY_TYPE,
				unique: "207c2294-970b-4e1f-82fd-ae8996ef171d", // Matches FormBuilderWeb.Controllers.ManagementApi.Security.Tree.SecurityTreeControllerBase.UsersFolderId
			});

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			eventContext.dispatchEvent(reloadEvent);
		}
		this._submitModal();
	}

	render() {
		return html`
			<umb-body-layout headline="${this.localize.term("formSecurity_deleteTitle", this.#userSecurityToDelete?.name)}">
				<uui-box>
					<p>${this.localize.term("formSecurity_deleteUserRecordNote")}</p>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term("general_cancel")} @click="${this._rejectModal}">${this.localize.term("general_cancel")}</uui-button>
				<uui-button slot="actions" type="button" label=${this.localize.term("general_delete")} look="primary" color="danger" @click=${this.#deleteUserSecurity}></uui-button>
			</umb-body-layout>
		`;
	}
}

export default FormsUserSecurityDeleteConfirmModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-user-security-delete-confirm-modal': FormsUserSecurityDeleteConfirmModalElement;
	}
}
